const HANDLES = [
  // AI labs
  'OpenAI','AnthropicAI','GoogleDeepMind','MistralAI','xai','Meta','nvidia',
  // Founders/researchers
  'sama','ylecun','DarioAmodei','karpathy','demishassabis','drjimfan','sundarpichai',
  // Video AI
  'runwayml','LumaLabsAI','Kling_ai','KLING_AI','midjourney','HeyGen_Official','pika_labs','HailuoAI_MiniMax','GenmoAI',
  // Audio AI
  'suno_ai_','ElevenLabsIO',
  // Image / dev
  'StabilityAI','blackforestlabs','ideogram_ai',
  // News/analysts
  'rowancheung','DrJimFan'
];

const handlesList = HANDLES.join(', @');
const store = $getWorkflowStaticData('global');
const lastCheck = store.grokLastCheck || new Date(Date.now() - 12*3600*1000).toISOString();
const now = new Date().toISOString();
store.grokLastCheck = now;

const instruction = `Найди ЗНАЧИМЫЕ AI-новости за последние 12 часов (с ${lastCheck.slice(0,16)}) от X-аккаунтов: @${handlesList}. Интересуют ТОЛЬКО:\n- новые релизы моделей (видео, аудио, изображения, LLM)\n- новые фичи и обновления ИИ-инструментов\n- анонсы продуктов\n- значимые технические демо\n\nИгнорируй:\n- личные мнения без релиза\n- мемы, шутки\n- рекламу событий без продукта\n- общие размышления\n\nДля каждой найденной новости сделай web-поиск чтобы добрать контекст (что это за продукт, ссылки, цена, дата).\n\nВерни СТРОГО JSON: {\n  "posts": [\n    {\n      "headline": "короткий заголовок до 80 символов",\n      "source": "@handle",\n      "source_url": "ссылка на X-пост",\n      "summary": "2-3 предложения: что произошло, какие возможности",\n      "why_relevant": "1 предложение почему это важно для видеомейкера / контент-мейкера",\n      "extra_links": ["опциональные доп.ссылки на блог/сайт"]\n    }\n  ]\n}\n\nМаксимум 4 поста. Если ничего значимого — {"posts": []}.`;

const body = JSON.stringify({
  model: 'grok-4-fast-reasoning',
  input: instruction,
  tools: [
    { type: 'web_search' },
    { type: 'x_search' }
  ]
});

return [{ json: { body } }];

const data = $input.first().json;
const output = data.output || [];

// Find the message output (not tool calls)
let jsonText = '';
for (const o of output) {
  if (o.type === 'message' && Array.isArray(o.content)) {
    for (const c of o.content) {
      if (c.type === 'output_text' && c.text) {
        jsonText = c.text;
        break;
      }
    }
  }
  if (jsonText) break;
}

if (!jsonText) return [];

// Strip markdown fences if any
jsonText = jsonText.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();

let parsed;
try { parsed = JSON.parse(jsonText); } catch(e) { return []; }

const posts = parsed.posts || [];
if (!posts.length) return [];

// Dedupe against previously sent posts (by headline)
const store = $getWorkflowStaticData('global');
if (!store.sentGrokPosts) store.sentGrokPosts = [];
const sentSet = new Set(store.sentGrokPosts);
const fresh = posts.filter(p => p.headline && !sentSet.has(p.headline.toLowerCase().slice(0, 60)));

for (const p of fresh) {
  store.sentGrokPosts.push(p.headline.toLowerCase().slice(0, 60));
}
if (store.sentGrokPosts.length > 200) store.sentGrokPosts = store.sentGrokPosts.slice(-200);

return fresh.map(p => ({ json: p }));

const gpt = $input.first().json;
const post = gpt.choices?.[0]?.message?.content?.trim() || '';
const id = 'grok_' + Date.now() + '_' + Math.random().toString(36).slice(2,7);
return [{ json: { post, id } }];
